import{_ as i,c as l,o,a4 as t}from"./chunks/framework.I1cCAST3.js";const A=JSON.parse('{"title":"AI 设置","description":"","frontmatter":{},"headers":[],"relativePath":"docs/ai/settings/index.md","filePath":"docs/ai/settings/index.md"}'),a={name:"docs/ai/settings/index.md"},e=t('<h1 id="ai-设置" tabindex="-1">AI 设置 <a class="header-anchor" href="#ai-设置" aria-label="Permalink to &quot;AI 设置&quot;">​</a></h1><p>配置 AI 提供商、模型和交互模式，定制您的 AI 体验。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>在配置 AI 设置之前，请确保您已具备：</p><ul><li>已安装 Chaterm（支持 AI 功能的版本）</li><li>使用内置模型，或拥有至少一个模型提供商的 API 密钥或凭证（支持的提供商请参见 <a href="/docs/ai/llms/">模型配置</a>）</li><li>能够访问所选提供商的 API 端点的网络连接（或本地 Ollama 实例）</li></ul><hr><h2 id="创建新的-ai-对话" tabindex="-1">创建新的 AI 对话 <a class="header-anchor" href="#创建新的-ai-对话" aria-label="Permalink to &quot;创建新的 AI 对话&quot;">​</a></h2><p>每个 AI 对话都是一个独立的会话，拥有自己的模式、模型和上下文。您可以同时运行多个对话。</p><ol><li>点击左侧菜单中的**&quot;AI&quot;**打开 AI 对话面板。</li><li>点击面板顶部的**&quot;新建对话&quot;**按钮。</li><li>选择一种<strong>交互模式</strong>： <ul><li><strong>Command</strong> -- AI 为当前活跃终端生成命令</li><li><strong>Agent</strong> -- AI 自主执行多步骤任务</li></ul></li><li>从下拉列表中选择一个<strong>模型</strong>。只有已配置的模型才会显示。</li><li><em>（仅 Agent 模式）</em> 在输入框中输入 <code>@</code> 选择一台或多台<strong>目标主机</strong>。</li><li>输入您的消息并按 <strong>Enter</strong> 开始对话。</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>您可以同时打开多个对话，每个对话使用不同的模式或模型。这对于比较模型响应或处理并行任务非常有用。</p></div><p>各模式的详细说明请参见 <a href="/docs/ai/dialogs/">AI 对话</a>。</p><hr><h2 id="配置模型提供商" tabindex="-1">配置模型提供商 <a class="header-anchor" href="#配置模型提供商" aria-label="Permalink to &quot;配置模型提供商&quot;">​</a></h2><p>要使用 AI 功能，您需要至少配置一个模型提供商。</p><ol><li>点击右上角齿轮图标打开<strong>设置</strong>。</li><li>在左侧菜单中导航到**&quot;模型&quot;**选项卡。</li><li>点击**&quot;添加模型&quot;**。</li><li>从列表中选择一个 <strong>API 提供商</strong>： <ul><li><strong>LiteLLM</strong> -- 支持多种提供商的统一接口</li><li><strong>OpenAI</strong> -- OpenAI 兼容 API</li><li><strong>Bedrock</strong> -- Amazon Bedrock（企业级）</li><li><strong>Anthropic</strong> -- Anthropic API</li><li><strong>DeepSeek</strong> -- DeepSeek API</li><li><strong>Ollama</strong> -- 本地部署的模型</li></ul></li><li>填写所选提供商的<strong>认证信息</strong>（API 密钥、端点 URL、区域等）。</li><li>输入或选择<strong>模型名称</strong>。</li><li>点击**&quot;测试连接&quot;**验证配置。</li><li>测试成功后，点击**&quot;保存&quot;**。</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>请妥善保管您的 API 密钥。如果怀疑密钥已泄露，请立即向提供商申请轮换密钥，并在 Chaterm 中更新配置。</p></div><p>提供商的具体配置字段参考表和详细设置说明，请参见 <a href="/docs/ai/llms/">模型配置</a>。</p><hr><h2 id="导出聊天记录" tabindex="-1">导出聊天记录 <a class="header-anchor" href="#导出聊天记录" aria-label="Permalink to &quot;导出聊天记录&quot;">​</a></h2><p>您可以导出任何对话用于分享或存档。</p><ol><li>打开您想要导出的对话。</li><li>点击<strong>导出</strong>按钮（通常位于对话面板的右上角区域）。</li><li>选择导出格式和保存位置。</li></ol><p>导出的聊天记录会保留完整的对话内容，包括 AI 回复、命令和执行输出。</p><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/docs/ai/dialogs/">AI 对话</a> -- 深入了解 Command 和 Agent 模式</li><li><a href="/docs/ai/llms/">模型配置</a> -- 各提供商的设置指南和配置字段参考</li><li><a href="/docs/ai/preferences/">AI 偏好设置</a> -- 配置推理深度、自动执行、安全和代理设置</li></ul>',25),r=[e];function s(n,c,d,h,g,p){return o(),l("div",null,r)}const m=i(a,[["render",s]]);export{A as __pageData,m as default};
